    def classify_market(question):
        """Fallback keyword classifier."""
        q = question.lower()
        kw = [
            "temperature", "weather", "rain", "snow", "wind",
            "heat", "cold", "celsius", "fahrenheit", "degrees",
            "forecast", "precipitation", "humidity", "storm",
        ]
        return any(k in q for k in kw)

