def _log(msg):
    ts = datetime.now(timezone.utc).strftime("%H:%M:%S")
    entry = f"{ts}  {msg}"
    _state["activity_log"].append(entry)
    if len(_state["activity_log"]) > 200:
        _state["activity_log"] = _state["activity_log"][-200:]
    logger.info(msg)


