@app.route("/api/trades/latest")
def trades_latest():
    """Latest trades split by type: main-loop, agent, and overall.

    Checks both top-level fields and nested meta dict so nothing is missed.
    Does NOT mutate _trade_log entries.
    Query param: n=<int>  max per bucket, default 1, max 20
    """
    n = min(int(request.args.get("n", 1)), 20)
    recent = list(reversed(_trade_log[-200:])) if _trade_log else []

    def _meta(t):
        m = t.get("meta", {})
        return m if isinstance(m, dict) else {}

    def _is_main_loop(t):
        m = _meta(t)
        return "ev_addon_reasons" in t or "ev_addon_reasons" in m

    def _is_agent(t):
        m = _meta(t)
        signal = str(t.get("signal", "")).upper()
        agent_markers = ("SNIPE", "GFS_DELTA", "HEDGE", "OBS_CONFIRM", "OBS_KILL")
        return (
            any(marker in signal for marker in agent_markers)
            or any(k in t for k in ("sniper", "gfs_delta", "hedge", "agent_type"))
            or any(k in m for k in ("sniper", "gfs_delta", "hedge", "agent_type"))
        ) and not _is_main_loop(t)

    _proof_keys = [
        "ev_addon_used", "ev_addon_reasons",
        "min_ev_base_pp", "min_ev_final_pp",
        "depth_cap_applied", "depth_cap_value_usd",
        "spend_pre_cap", "spend_post_cap",
        "sigma_floor_used",
        "bias_correction_f", "bias_confidence",
        "station_drifting", "drift_shift_f",
        "station_rmse", "station_n",
    ]

    def _decorate(trades):
        out = []
        for t in trades:
            row = dict(t)           # shallow copy — never mutate original
            m = _meta(t)
            proof = {}
            for k in _proof_keys:
                if k in row:
                    proof[k] = row[k]
                elif k in m:
                    proof[k] = m[k]
            row["_proof"] = proof
            row["_proof_fields_present"] = list(proof.keys())
            out.append(row)
        return out

    main_loop = _decorate([t for t in recent if _is_main_loop(t)][:n])
    agent     = _decorate([t for t in recent if _is_agent(t)][:n])
    overall   = _decorate(recent[:n])

    return jsonify({
        "ok": True,
        "boot_id": BOOT_ID,
        "commit": GIT_COMMIT,
        "main_loop": {"count": len(main_loop), "trades": main_loop},
        "agent":     {"count": len(agent),     "trades": agent},
        "overall":   {"count": len(overall),   "trades": overall},
    })


@app.route("/api/trades/latest_db")
def trades_latest_db():
    """Same as /api/trades/latest but reads from ledger.db — survives restarts.

    Query param: n=<int>  rows to return, default 5, max 50
    """
    if not HAS_LEDGER:
        return jsonify({"ok": False, "error": "ledger not available"}), 503
    import sqlite3 as _sq, json as _json
    n = min(int(request.args.get("n", 5)), 50)
    _proof_keys = [
        "ev_addon_used", "ev_addon_reasons",
        "min_ev_base_pp", "min_ev_final_pp",
        "depth_cap_applied", "depth_cap_value_usd",
        "spend_pre_cap", "spend_post_cap",
        "sigma_floor_used",
        "bias_correction_f", "bias_confidence",
        "station_drifting", "drift_shift_f",
        "station_rmse", "station_n",
    ]
    try:
        import trade_ledger as _tl
        conn = _sq.connect(_tl.DB_PATH, check_same_thread=False)
        conn.row_factory = _sq.Row
        rows = conn.execute(
            "SELECT * FROM trades ORDER BY id DESC LIMIT ?", (max(n * 10, 50),)
        ).fetchall()
        conn.close()
    except Exception as exc:
        return jsonify({"ok": False, "error": str(exc)}), 500

    def _parse_row(row):
        d = dict(row)
        raw_meta = d.pop("meta", None)
        m = {}
        if raw_meta:
            try:
                m = _json.loads(raw_meta)
            except Exception:
                pass
        d["meta"] = m
        # Bubble proof fields up to top-level _proof dict
        proof = {}
        for k in _proof_keys:
            if k in d:
                proof[k] = d[k]
            elif k in m:
                proof[k] = m[k]
        d["_proof"] = proof
        d["_proof_fields_present"] = list(proof.keys())
        d["_is_main_loop"] = "ev_addon_reasons" in proof
        return d

    parsed = [_parse_row(r) for r in rows]
    main_loop = [r for r in parsed if r["_is_main_loop"]][:n]
    other     = [r for r in parsed if not r["_is_main_loop"]][:n]
    overall   = parsed[:n]

    return jsonify({
        "ok": True,
        "boot_id": BOOT_ID,
        "commit": GIT_COMMIT,
        "source": "ledger.db",
        "main_loop": {"count": len(main_loop), "trades": main_loop},
        "other":     {"count": len(other),     "trades": other},
        "overall":   {"count": len(overall),   "trades": overall},
    })


@app.route("/api/trades/latest_db_main")
def trades_latest_db_main():
    """Return only main-loop coordinator trades from ledger.db.
    Skips agent trades (SNIPE, NO_HARVEST, EXIT, GFS, OBS_CONFIRM).
    Query param: n=<int> rows, default 5, max 20
    """
    if not HAS_LEDGER:
        return jsonify({"ok": False, "error": "ledger not available"}), 503
    import sqlite3 as _sq, json as _json
    n = min(int(request.args.get("n", 5)), 20)
    _proof_keys = [
        "ev_addon_used", "ev_addon_reasons",
        "min_ev_base_pp", "min_ev_final_pp",
        "depth_cap_applied", "depth_cap_value_usd",
        "spend_pre_cap", "spend_post_cap",
        "sigma_floor_used",
        "bias_correction_f", "bias_confidence",
        "station_drifting", "drift_shift_f",
        "station_rmse", "station_n",
    ]
    _agent_signals = {"SNIPE_YES", "SNIPE_NO", "NO_HARVEST", "EXIT_SELL_ALL",
                      "GFS_DELTA_YES", "GFS_DELTA_NO", "OBS_CONFIRM_YES", "OBS_CONFIRM_NO",
                      "HEDGE_YES", "HEDGE_NO"}
    try:
        import trade_ledger as _tl
        conn = _sq.connect(_tl.DB_PATH, check_same_thread=False)
        conn.row_factory = _sq.Row
        # Fetch more rows to find n main-loop trades among agent trades
        rows = conn.execute(
            "SELECT * FROM trades ORDER BY id DESC LIMIT ?", (max(n * 20, 100),)
        ).fetchall()
        conn.close()
    except Exception as exc:
        return jsonify({"ok": False, "error": str(exc)}), 500

    results = []
    for row in rows:
        d = dict(row)
        sig = d.get("signal", "")
        # Skip known agent signals
        if sig in _agent_signals:
            continue
        raw_meta = d.pop("meta", None)
        m = {}
        if raw_meta:
            try:
                m = _json.loads(raw_meta)
            except Exception:
                pass
        d["meta"] = m
        proof = {k: (d[k] if k in d else m[k]) for k in _proof_keys if k in d or k in m}
        d["_proof"] = proof
        d["_proof_fields_present"] = list(proof.keys())
        results.append(d)
        if len(results) >= n:
            break

    return jsonify({
        "ok": True,
        "boot_id": BOOT_ID,
        "commit": GIT_COMMIT,
        "source": "ledger.db",
        "count": len(results),
        "trades": results,
    })


@app.route("/api/stats/reliability")
def stats_reliability():
    """Station reliability measurement and tuning metrics.

    Returns:
    - win_rate by ev_addon_reasons bucket (LOW_N, NOISY, DRIFT, clean)
    - avg spend_vs_depth_ratio per bucket (spend_pre_cap / depth_cap_value_usd)
    - avg ev_gate_delta per bucket (min_ev_final_pp - min_ev_base_pp)
    - trade_source breakdown counts
    - overall win/loss/pending counts
    """
    if not HAS_LEDGER:
        return jsonify({"ok": False, "error": "ledger not available"}), 503
    import sqlite3 as _sq, json as _json
    from collections import defaultdict
    try:
        import trade_ledger as _tl
        conn = _sq.connect(_tl.DB_PATH, check_same_thread=False)
        conn.row_factory = _sq.Row
        rows = conn.execute("SELECT * FROM trades ORDER BY id DESC LIMIT 500").fetchall()
        conn.close()
    except Exception as exc:
        return jsonify({"ok": False, "error": str(exc)}), 500

    buckets = defaultdict(lambda: {"trades": 0, "won": 0, "lost": 0, "pending": 0,
                                    "ev_gate_deltas": [], "spend_depth_ratios": []})
    source_counts = defaultdict(int)
    overall = {"trades": 0, "won": 0, "lost": 0, "pending": 0}

    for row in rows:
        d = dict(row)
        raw_meta = d.get("meta") or "{}"
        try:
            m = _json.loads(raw_meta)
        except Exception:
            m = {}

        # trade_source — explicit field (new) or infer from signal (old trades)
        source = m.get("trade_source") or d.get("signal", "")
        if source not in ("main_loop", "agent", "exit_engine"):
            sig = d.get("signal", "")
            if sig in ("BUY YES", "BUY NO"):
                source = "main_loop"
            elif sig.startswith("EXIT"):
                source = "exit_engine"
            else:
                source = "agent"
        source_counts[source] += 1

        won = d.get("won")
        overall["trades"] += 1
        if won == 1:
            overall["won"] += 1
        elif won == 0:
            overall["lost"] += 1
        else:
            overall["pending"] += 1

        # Only bucket main_loop trades — those are the ones with reliability knobs
        if source != "main_loop":
            continue

        # Determine bucket from ev_addon_reasons
        reasons = m.get("ev_addon_reasons") or []
        if isinstance(reasons, str):
            try:
                reasons = _json.loads(reasons)
            except Exception:
                reasons = [reasons] if reasons else []
        if not reasons:
            bucket_key = "clean"
        elif "DRIFT" in reasons:
            bucket_key = "DRIFT"
        elif "NOISY" in reasons:
            bucket_key = "NOISY"
        elif "LOW_N" in reasons:
            bucket_key = "LOW_N"
        else:
            bucket_key = "+".join(sorted(reasons))

        b = buckets[bucket_key]
        b["trades"] += 1
        if won == 1:
            b["won"] += 1
        elif won == 0:
            b["lost"] += 1
        else:
            b["pending"] += 1

        # EV gate delta: how much did reliability raise the gate?
        base = m.get("min_ev_base_pp", 0)
        final = m.get("min_ev_final_pp", 0)
        if base and final:
            b["ev_gate_deltas"].append(round(final - base, 2))

        # Spend vs depth ratio: how much of available depth did we use?
        spend_pre = m.get("spend_pre_cap", 0)
        depth_cap = m.get("depth_cap_value_usd", 0)
        if spend_pre and depth_cap and depth_cap > 0:
            b["spend_depth_ratios"].append(round(spend_pre / depth_cap, 2))

    # Summarise buckets
    bucket_summary = {}
    for k, b in buckets.items():
        n_resolved = b["won"] + b["lost"]
        bucket_summary[k] = {
            "trades": b["trades"],
            "won": b["won"],
            "lost": b["lost"],
            "pending": b["pending"],
            "win_rate_pct": round(100 * b["won"] / n_resolved, 1) if n_resolved else None,
            "avg_ev_gate_delta_pp": round(sum(b["ev_gate_deltas"]) / len(b["ev_gate_deltas"]), 2)
                                    if b["ev_gate_deltas"] else None,
            "avg_spend_depth_ratio": round(sum(b["spend_depth_ratios"]) / len(b["spend_depth_ratios"]), 2)
                                     if b["spend_depth_ratios"] else None,
        }

    return jsonify({
        "ok": True,
        "boot_id": BOOT_ID,
        "note": "win_rate requires resolved trades — pending means unresolved",
        "overall": overall,
        "by_reliability_bucket": bucket_summary,
        "trade_source_counts": dict(source_counts),
    })


def _start_position_monitor():
    """Monitor open positions every 5 min, exit losers via active_trader rules."""
    import threading
    def _monitor_loop():
        while True:
            time.sleep(300)  # 5 minutes
            if not ACTIVE_TRADER_AVAILABLE or not _auto_trade_active:
                continue
            try:
                # Monitor ALL trades (PAPER + LIVE) so paper mode behaves like real trading
                open_trades = [t for t in _trade_log if isinstance(t, dict) and t.get("mode") in ("LIVE", "PAPER") and not t.get("exited")]
                if not open_trades:
                    continue
                now_utc = datetime.now(timezone.utc)
                positions = []
                for t in open_trades[-50:]:
                    city = t.get("city", "")
                    entry_price = t.get("price", 0.5)
                    entry_cost = entry_price * t.get("size", 1)
                    threshold = t.get("threshold", 0) or 0
                    token_id = t.get("token_id", "")
                    # Fetch LIVE current price from CLOB order book
                    current_price = entry_price  # fallback
                    if HAS_CLOB_BOOK and token_id:
                        try:
                            _book = clob_book.get_book(token_id)
                            if _book and _book.get("bids"):
                                # Best bid = what we could sell for right now
                                current_price = float(_book["bids"][0]["price"])
                        except Exception:
                            pass
                    current_value = current_price * t.get("size", 1)
                    # Estimate minutes to resolution from trade timestamp
                    trade_ts = t.get("timestamp", time.time())
                    age_min = (time.time() - trade_ts) / 60.0
                    est_resolution_min = max(0, 1440 - age_min)  # ~24h markets
                    positions.append({
                        "city": city,
                        "bin_lo": threshold - 1,
                        "bin_hi": threshold + 1,
                        "entry_price": entry_price,
                        "current_price": current_price,
                        "entry_cost": entry_cost,
                        "current_value": current_value,
                        "mins_to_resolution": est_resolution_min,
                        "token_id": token_id,
                        "_trade_ref": t,  # reference back so we can mark exited
                        # Forecast data for smart exit decisions
                        "our_prob": t.get("our_prob", 0),
                        "signal": t.get("signal", ""),
                        "ev": t.get("ev", 0),
                        "direction": t.get("direction", ""),
                    })
                exit_actions = run_position_monitor(positions)
                for action in exit_actions:
                    logger.warning("POSITION_MONITOR EXIT: %s | %s | %s",
                                   action.get("city"), action.get("action"), action.get("reason"))
                    # Mark the trade as exited so we don't keep re-evaluating it
                    _tref = action.get("_trade_ref")
                    if _tref and isinstance(_tref, dict):
                        _tref["exited"] = True
                        _tref["exit_reason"] = action.get("reason", "")
                        _tref["exit_action"] = action.get("action", "")
                        _tref["exit_price"] = action.get("current_price", 0)
                        _tref["exit_ts"] = time.time()
                    is_paper = _tref and _tref.get("mode") == "PAPER" if _tref else False
                    if is_paper:
                        # Paper mode: log the simulated exit + record in ledger
                        _exit_price = action.get("current_price", 0)
                        _entry_price = _tref.get("price", 0) if _tref else 0
                        _size = _tref.get("size", 1) if _tref else 1
                        _pnl = round((_exit_price - _entry_price) * _size, 4)
                        logger.info("PAPER EXIT: %s | %s | entry=%.3f exit=%.3f size=%.0f pnl=%.4f | %s",
                                    action.get("city"), action.get("action"),
                                    _entry_price, _exit_price, _size, _pnl, action.get("reason"))
                        if HAS_LEDGER:
                            try:
                                trade_ledger.record_trade({
                                    'ts': datetime.now(timezone.utc).isoformat(),
                                    'question': f"EXIT: {action.get('city', '')} | {action.get('reason', '')}",
                                    'city': action.get("city", ""),
                                    'signal': f"EXIT_{action.get('action', 'SELL')}",
                                    'trade_source': 'exit_engine',
                                    'token_id': action.get("token_id", ""),
                                    'price': _exit_price, 'size': _size,
                                    'ev': 0, 'ev_dollar': 0,
                                    'our_prob': 0, 'mkt_price': round(_exit_price * 100, 1),
                                    'mode': 'PAPER',
                                })
                            except Exception:
                                pass
                    elif _clob_client and action.get("action") in ("SELL_ALL", "SELL_HALF"):
                        # LIVE mode: actually execute the sell
                        try:
                            from py_clob_client.order_builder.constants import SELL as _SELL_SIDE
                            from py_clob_client.clob_types import OrderArgs
                            tok = action.get("token_id", "")
                            if tok:
                                sell_args = OrderArgs(price=0.01, size=1, side=_SELL_SIDE, token_id=tok)
                                sell_resp = _clob_client.create_and_post_order(sell_args)
                                logger.info("SELL executed: %s => %s", tok[:12], str(sell_resp)[:100])
                        except Exception as sell_err:
                            logger.error("SELL failed: %s", sell_err)
                # Ruflo Agent 2: live price check ÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ STOP_LOSS / PROFIT_TAKE / TIME_EXIT
                if RUFLO_AVAILABLE:
                    try:
                        _ruflo_alerts = _ruflo_position_monitor.check_positions()
                        for _ra in _ruflo_alerts:
                            if _ra.get('alert') == 'ERROR':
                                logger.debug("Ruflo position error: %s", _ra.get('msg'))
                            else:
                                logger.warning("RUFLO_%s: %s | %s (entry=%.3f current=%.3f)",
                                    _ra.get('alert', '?'), _ra.get('market', '')[:40],
                                    _ra.get('reason', ''), _ra.get('entry', 0), _ra.get('current', 0))
                    except Exception as _re2:
                        logger.debug("Ruflo Agent2 position monitor error: %s", _re2)
            except Exception as e:
                logger.error("Position monitor loop error: %s", e)
    t = threading.Thread(target=_monitor_loop, daemon=True)
    t.start()
    logger.info("Position monitor started (every 5 min)")



